var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>인히비터 프로토콜 일시 침묵.</color>","JPN":"<color=#ff3636>インヒビタープロトコル一時沈黙。</color>","ENG":"<color=#ff3636>Inhibitor Protocol paused.</color>","TWN":"<color=#ff3636>抑制者協議暫時沉默。</color>"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYS_NPC_NULL_NULL","text":{"KOREA":"<color=#ff3636>프로토콜 재시작까지 약 120초.</color>","JPN":"<color=#ff3636>プロトコル再開始まで約120秒。</color>","ENG":"<color=#ff3636>Restarting Protocol in approximately 120 seconds.</color>","TWN":"<color=#ff3636>協定重啟大約需要120秒。</color>"},"stage":{"bg":"MIND","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"제길, 대체 여긴 어떻게 돼먹은 공간이야……?","JPN":"くそ、いったいここはどういう空間なんだ……？","ENG":"Damn it... what is this place?","TWN":"該死，這到底是什麼鬼地方……？！"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이 기계 녀석들은 다 어디서 기어 나오는 건데? 부셔도, 부셔도 끝이 없잖아?","JPN":"この機械のやつら、どこから沸いてくるの？　壊しても壊してもキリがない！","ENG":"Where are all these machines even coming from? I destroy one, and three more show up.","TWN":"這些機械傢伙到底是從哪裡冒出來的？怎麼打也打不完啊？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"유미나, 뭔가 이상하지 않나?","JPN":"ヤナギ・ミナ、おかしいと思わないか？","ENG":"Yoo Mina, doesn't something feel off?","TWN":"劉米娜，不覺得有些奇怪嗎？"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"현실에서 녀석들을 쓰러트릴 때와 무기에 실리는 감촉이 달라.","JPN":"現実でやつらを倒す時とは手応えが違う。","ENG":"The impact feels different from when we fight them in reality.","TWN":"在現實中擊敗他們時，武器的感覺是不同的。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"또한 그렇게 많은 기체를 파괴했는데, 녀석들의 부서진 잔해는 어디에 있지?","JPN":"それに、あれほど大量の機体を破壊したのに、壊れたやつらの残骸はどこへ消えたのだ？","ENG":"And despite all the machines we've taken down... where are the wrecks?","TWN":"而且破壞了那麼多機體，那些傢伙的破碎殘骸在哪裡呢？"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그러고 보니…….","JPN":"言われてみれば……","ENG":"Now that you mention it...","TWN":"這麼說來……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"아무래도 이곳은 현실의 물리 법칙이 적용되지 않는 일종의 가상 공간…….","JPN":"どうやらここは現実の物理法則の影響を受けない、一種の仮想空間……","ENG":"This place seems like a virtual space that doesn't obey the physical laws of reality.","TWN":"看來這裡是一個不受現實物理法則約束的虛擬空間……"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"클리파 차원인 것 같다.","JPN":"クリファ次元のようだ。","ENG":"It feels like... we're inside the Qlipha Dimension.","TWN":"好像是逆卡巴拉次元。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여기가 클리파 차원이라고?","JPN":"ここがクリファ次元？","ENG":"This is the Qlipha Dimension?","TWN":"這裡是逆卡巴拉次元？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"그래. 아마도 저 공중에 매달린 거대한 머리가 이 가상 공간을 통제하고 있겠지.","JPN":"ああ。おそらく、あの宙にぶら下がっている巨大な頭がこの仮想空間をコントロールしているのだろう。","ENG":"Yes. That massive floating head up there is likely controlling this virtual space.","TWN":"是啊，可能那懸浮在空中的巨大頭顱正在控制這個虛擬空間吧。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"다시 말해, 지금까지 우리가 싸운 기체들은 전부 허상이었다는 거다.","JPN":"つまり、今まで私たちが戦った相手はすべて幻だったということだ。","ENG":"Which means everything we've been fighting so far was just an illusion.","TWN":"換句話說，到目前為止和我們對戰的機體全都是幻影。"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"자, 잠깐만요……!","JPN":"ま、待ってください……！","ENG":"W-wait, hold on...!","TWN":"等，等一下……！"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"허상이라니… 그럼, 여기가 바루나스트라의 뱃속이랑 다를 바 없다는 뜻인가요?","JPN":"幻って……じゃあ、ここはヴァルナストラのお腹の中みたいな所ってことですか？","ENG":"An illusion? Then this place is no different from being inside Varunastra's belly?","TWN":"幻象嗎……那就是說，這裡和伐樓拿之艦的內部是一樣的嗎？"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"살면서 두 번이나 이런 곳에 떨어질 줄이야!","JPN":"生きて2回もこんな場所に落とされるなんて！","ENG":"Seriously, what are the odds I'd end up in this kind of place twice?!","TWN":"沒想到我這輩子會掉到這種地方兩次！"},"stage":{"bg":"MIND","slots":{"L":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"아샤, 이터니움 실드의 잔량을 확인하도록.","JPN":"アーシャ、エタニウムシールドの残量を確認してくれ。","ENG":"Asha, check your Eternium shield.","TWN":"阿莎，確認永恆之金護盾的剩餘量。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"클리파 차원은 초고심도의 침식지대나 다를 바 없는 곳이다.","JPN":"クリファ次元は、超高深度の侵食地帯も同然だ。","ENG":"The Qlipha Dimension is basically no different from hyperdepths of a Corrupted Area.","TWN":"逆卡巴拉次元是與超高深度的侵蝕地帶無異的地方。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"워치가 없는 일반인이 머물 수 있는 곳이 아니야. 후유증이 생길 수도 있어.","JPN":"ウォッチのない一般人が滞在できる場所ではない。後遺症が残る恐れがある。","ENG":"This isn't a place a non-Counter without a Watch should be in. The aftereffects could be serious.","TWN":"這裡不是沒有能量環的普通人能待的地方。可能會有後遺症。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ASHA_VARUNA_NULL_NULL","text":{"KOREA":"후, 후유증이라고요……?","JPN":"こ、後遺症……？","ENG":"A-aftereffects...?","TWN":"後，後遺症嗎……？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"ASHA_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"어쨌든 저 공중에 매달린 머리를 박살내 버리면, 여기서 탈출할 수 있다는 뜻이지?","JPN":"とにかく、あの宙にぶら下がってる頭をぶち壊せばここから出れるってことだよね？","ENG":"Anyway, if we smash that giant floating head, we can escape from here, right?","TWN":"總之，只要把那懸在空中的頭顱打碎，就能從這裡逃脫，對吧？"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"좋아, 그럼 나한테 맡기라고.","JPN":"よし、じゃあ私に任せて。","ENG":"Great. Then leave it to me.","TWN":"好，那就交給我吧。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"클리파 차원이라면, 몇 번쯤 경험해 본 적이 있으니까.","JPN":"クリファ次元なら、何回か経験したことがあるから。","ENG":"I've dealt with the Qlipha Dimension more than a few times.","TWN":"如果是逆卡巴拉次元的話，我有過幾次經驗。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SURYA_VARUNA_NULL_NULL","text":{"KOREA":"아니, 여기선 내가 길을 열어주지.","JPN":"いや、ここは私が道を開こう。","ENG":"No, let me handle this. I'll clear a path for you.","TWN":"不，這裡由我來開路。"},"stage":{"bg":"MIND","slots":{"L":null,"C":{"char_id":"SURYA_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};